  array[N] int&lt;lower=1,upper=3&gt; spp_id;
}
parameters {
  vector[3] mu;
  real&lt;lower=0&gt; sigma;
}
model {
  measurements ~ normal(mu[spp_id], sigma);
  mu ~ normal(17,2);
  sigma ~ exponential(1);
