surv &lt;- c(3, 4, 5)

calc_ll &lt;- function(x) {
  res &lt;- sum(-dbinom(surv, 5,
                     prob = x,
                     log = TRUE))
  return(res)
}

prob_val &lt;- seq(from = 0, to = 1,
                length.out = 30)
log_lik &lt;- numeric(30L)

for (i in 1:length(prob_val)) {
  log_lik[i] &lt;- calc_ll(prob_val[i])
}
par(cex = 3)
plot(prob_val, log_lik, type = "b")
